(()=>{var e=document.querySelector(".button-open-side-menu"),n=(document.querySelector(".button-open-side-menu__burger-line"),document.querySelector(".nav")),o=document.querySelectorAll(".nav > div > a");e.addEventListener("click",(function(){e.classList.toggle("close-burger"),n.classList.toggle("show-side-menu")})),o.forEach((function(o){o.addEventListener("click",(function(){n.classList.toggle("show-side-menu"),e.classList.toggle("close-burger")}))}));var t=window.innerHeight-50;window.addEventListener("scroll",(function(){window.scrollY>t&&(e.style.backgroundColor="#1E1D3E",e.style.borderRadius="10rem")}))})();